import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public void displayMessage(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("message");
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput); // Sanitize user input

        String htmlResponse = "<html><body><p>" + sanitizedInput + "</p></body></html>";

        response.setContentType("text/html");
        response.getWriter().write(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
